void* alloc(size_t size) {
    void* ptr = NULL;
    ptr = malloc(size);
    if(NULL == ptr) {
        perror("malloc");
        exit(-1);
    }
    return ptr;
}

int cl_errChk(const int status, const char * msg, bool exitOnErr) {
    if(status != 0) {
        printf("CUDA Error: %d %s\n", status, msg);
        if(exitOnErr) {
            exit(-1);
        }
        return true;
    }
    return false;
}

// Helper for timeval subtraction
void tvsub(struct timeval *t1, struct timeval *t2, struct timeval *res) {
    res->tv_sec = t1->tv_sec - t2->tv_sec;
    res->tv_usec = t1->tv_usec - t2->tv_usec;
    if (res->tv_usec < 0) {
        res->tv_sec--;
        res->tv_usec += 1000000;
    }
}

// CUDA Kernel for Fan1
__global__ void Fan1_kernel(float *data_11,
                            float *val_10,
                            float *item_4,
                            const int data_2,
                            const int t) {
    int item_5 = blockIdx.x * blockDim.x + threadIdx.x;

    if (data_2 - 1 - t > item_5) {
        int row = item_5 + t + 1;
        int col = t;
        data_11[data_2 * row + col] = val_10[data_2 * row + col] / val_10[data_2 * t + t];
    }
}

// CUDA Kernel for Fan2
__global__ void Fan2_kernel(float *elem_9,
                            float *elem_0,
                            float *item_1,
                            const int item_7,
                            const int t) {
    int x_6 = blockIdx.x * blockDim.x + threadIdx.x;
    int x_8 = blockIdx.y * blockDim.y + threadIdx.y;

    if (item_7 - 1 - t > x_6 && item_7 - t > x_8) {
        int row_a = x_6 + 1 + t;
        int col_a = x_8 + t;
        int row_m = x_6 + 1 + t;
        int col_m = t;
        int row_a_src = t;
        int col_a_src = x_8 + t;

        elem_0[item_7 * row_a + col_a] -= elem_9[item_7 * row_m + col_m] * elem_0[item_7 * row_a_src + col_a_src];

        if (0 == x_8) {
            item_1[x_6 + 1 + t] -= elem_9[item_7 * row_a + col_a] * item_1[t];
        }
    }
}

// Helper functions from Source File 4 (main logic)
void InitPerRun(int size, float *m) {
    int i;
    for (i = 0; i < size * size; i++) {
        m[i] = 0.0;
    }
}

void InitMat(FILE *fp, int size, float *ary, int nrow, int ncol) {
    int i, j;
    for (i = 0; i < nrow; i++) {
        for (j = 0; j < ncol; j++) {
            fscanf(fp, "%f", &ary[size * i + j]);
        }
    }
}

void InitAry(FILE *fp, float *ary, int ary_size) {
    int i;
    for (i = 0; i < ary_size; i++) {
        fscanf(fp, "%f", &ary[i]);
    }
}

void PrintMat(float *ary, int size, int nrow, int ncol) {
    int i, j;
    for (i = 0; i < nrow; i++) {
        for (j = 0; j < ncol; j++) {
            printf("%8.2e ", ary[size * i + j]);
        }
        printf("\n");
    }
    printf("\n");
}

void PrintAry(float *ary, int ary_size) {
    int i;
    for (i = 0; i < ary_size; i++) {
        printf("%.2e ", ary[i]);
    }
    printf("\n\n");
}

void BackSub(float *a, float *b, float *finalVec, int size) {
    int i, j;
    for (i = 0; i < size; i++) {
        finalVec[size - i - 1] = b[size - i - 1];
        for (j = 0; j < i; j++) {
            finalVec[size - i - 1] -= a[size * (size - i - 1) + (size - j - 1)] * finalVec[size - j - 1];
        }
        finalVec[size - i - 1] = finalVec[size - i - 1] / a[size * (size - i - 1) + (size - i - 1)];
    }
}

void create_matrix(float *m, int size) {
    int i, j;
    float lamda = -0.01;
    float *coe = (float *)malloc((2 * size) * sizeof(float));
    float coe_i = 0.0;

    for (i = 0; i < size; i++) {
        coe_i = 10 * exp(lamda * i);
        j = size - 1 + i;
        coe[j] = coe_i;
        j = size - 1 - i;
        coe[j] = coe_i;
    }

    for (i = 0; i < size; i++) {
        for (j = 0; j < size; j++) {
            m[i * size + j] = coe[size - 1 - i + j];
        }
    }
    free(coe);
}

int parseCommandline(int argc, char *argv[], char* filename,
                     int *q, int *v, int *t, int *p, int *d, int *size) {
    int i;
    if (2 > argc) return 1;
    char flag;

    for (i = 1; i < argc; i++) {
        if ('-' == argv[i][0]) {
            flag = argv[i][1];
            switch (flag) {
                case 's':
                    i++;
                    *size = atoi(argv[i]);
                    printf("Create matrix internally in parse, size = %d \n", *size);
                    break;
                case 'f':
                    i++;
                    strncpy(filename, argv[i], 100);
                    printf("Read file from %s \n", filename);
                    break;
                case 'h':
                    return 1;
                    break;
                case 'q':
                    *q = 1;
                    break;
                case 'v':
                    *v = 1;
                    break;
                case 't':
                    *t = 1;
                    break;
                case 'p':
                    i++;
                    *p = atoi(argv[i]);
                    break;
                case 'd':
                    i++;
                    *d = atoi(argv[i]);
                    break;
            }
        }
    }
    if ((0 <= *d && 0 > *p) || (0 <= *p && 0 > *d))
        return 1;
    return 0;
}

