#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_init_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time= 0,
      d2h_time = 0, close_time = 0, total_time = 0;

cudaEvent_t event_start, event_end;

float eventTime(cudaEvent_t start, cudaEvent_t end) {
    float elapsed = 0.0f;
    cudaEventSynchronize(end);
    cudaEventElapsedTime(&elapsed, start, end);
    return elapsed;
}
#endif

void ForwardSub(float *a, float *b, float *m, int size, int timing) {
    float *a_dev, *b_dev, *m_dev;
    cudaError_t err;

    // Block sizes (defaulting to 1 if not defined, mimicking the OpenCL macro logic)
    int BLOCK_SIZE_0 = 256; // Default reasonable value
    int BLOCK_SIZE_1_X = 16;
    int BLOCK_SIZE_1_Y = 16;

    size_t globalWorksizeFan1[1];
    dim3 globalWorksizeFan2;
    dim3 localWorksizeFan2(BLOCK_SIZE_1_X, BLOCK_SIZE_1_Y);

    globalWorksizeFan1[0] = size;
    globalWorksizeFan2 = dim3(size, size, 1);

#ifdef TIMING
    cudaEventCreate(&event_start);
    cudaEventCreate(&event_end);
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    // Allocate device memory
    err = cudaMalloc((void**)&a_dev, sizeof(float) * size * size);
    cl_errChk((int)err, "Allocating a_dev", true);
    err = cudaMalloc((void**)&b_dev, sizeof(float) * size);
    cl_errChk((int)err, "Allocating b_dev", true);
    err = cudaMalloc((void**)&m_dev, sizeof(float) * size * size);
    cl_errChk((int)err, "Allocating m_dev", true);

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    float writeMB = (float)(sizeof(float) * size * (size + size + 1) / 1e6);
    float readMB = (float)(sizeof(float) * size * (size + size + 1) / 1e6);

#ifdef TIMING
    gettimeofday(&tv_h2d_start, NULL);
    cudaEventRecord(event_start);
#endif

    // Copy data to device
    err = cudaMemcpy(a_dev, a, sizeof(float) * size * size, cudaMemcpyHostToDevice);
    cl_errChk((int)err, "Copying a to device", true);
    err = cudaMemcpy(b_dev, b, sizeof(float) * size, cudaMemcpyHostToDevice);
    cl_errChk((int)err, "Copying b to device", true);
    err = cudaMemcpy(m_dev, m, sizeof(float) * size * size, cudaMemcpyHostToDevice);
    cl_errChk((int)err, "Copying m to device", true);

#ifdef TIMING
    cudaEventRecord(event_end);
    cudaEventSynchronize(event_end);
    h2d_time += eventTime(event_start, event_end);
    gettimeofday(&tv_h2d_end, NULL);
#endif

    int t;
    for (t = 0; t < size - 1; t++) {
        // Fan1
        int threadsPerBlock1 = BLOCK_SIZE_0;
        int blocksPerGrid1 = (size + threadsPerBlock1 - 1) / threadsPerBlock1;

#ifdef TIMING
        cudaEventRecord(event_start);
#endif

        Fan1_kernel<<<blocksPerGrid1, threadsPerBlock1>>>(m_dev, a_dev, b_dev, size, t);
        err = cudaGetLastError();
        cl_errChk((int)err, "Executing Fan1 Kernel", true);

#ifdef TIMING
        cudaEventRecord(event_end);
        cudaEventSynchronize(event_end);
        kernel_time += eventTime(event_start, event_end);
#endif

        // Fan2
        dim3 threadsPerBlock2(BLOCK_SIZE_1_X, BLOCK_SIZE_1_Y);
        dim3 blocksPerGrid2((size + BLOCK_SIZE_1_X - 1) / BLOCK_SIZE_1_X, 
                            (size + BLOCK_SIZE_1_Y - 1) / BLOCK_SIZE_1_Y);

#ifdef TIMING
        cudaEventRecord(event_start);
#endif

        Fan2_kernel<<<blocksPerGrid2, threadsPerBlock2>>>(m_dev, a_dev, b_dev, size, t);
        err = cudaGetLastError();
        cl_errChk((int)err, "Executing Fan2 Kernel", true);

#ifdef TIMING
        cudaEventRecord(event_end);
        cudaEventSynchronize(event_end);
        kernel_time += eventTime(event_start, event_end);
#endif

        // Ensure completion before next iteration
        cudaDeviceSynchronize();
    }

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
    cudaEventRecord(event_start);
#endif

    // Copy data back to host
    err = cudaMemcpy(a, a_dev, sizeof(float) * size * size, cudaMemcpyDeviceToHost);
    cl_errChk((int)err, "Copying a to host", true);
    err = cudaMemcpy(b, b_dev, sizeof(float) * size, cudaMemcpyDeviceToHost);
    cl_errChk((int)err, "Copying b to host", true);
    err = cudaMemcpy(m, m_dev, sizeof(float) * size * size, cudaMemcpyDeviceToHost);
    cl_errChk((int)err, "Copying m to host", true);

#ifdef TIMING
    cudaEventRecord(event_end);
    cudaEventSynchronize(event_end);
    d2h_time += eventTime(event_start, event_end);
    gettimeofday(&tv_d2h_end, NULL);
#endif

    // Cleanup
#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif
    cudaFree(a_dev);
    cudaFree(b_dev);
    cudaFree(m_dev);
#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    printf("Matrix Size\tWrite(s) [size]\t\tKernel(s)\tRead(s)  [size]\t\tTotal(s)\n");
    printf("%dx%d      \t",size,size);
    printf("%f [%.2fMB]\t",h2d_time,writeMB);
    printf("%f\t",kernel_time);
    printf("%f [%.2fMB]\t",d2h_time,readMB);
    printf("%f\n\n",h2d_time+kernel_time+d2h_time);
#endif
}

int main(int argc, char *argv[]) {
    float *a = NULL, *b = NULL, *finalVec = NULL;
    float *m = NULL;
    int size = -1;
    FILE *fp;
    char filename[200];
    int show_data = 0, quiet = 0, timing = 0, platform = 0, device = 0;

    printf("WG size of kernel 1 = %d, WG size of kernel 2= %d X %d\n", 256, 16, 16);

    if (parseCommandline(argc, argv, filename,
                         &quiet, &show_data, &timing, &platform, &device, &size)) {
        printUsage();
        return 0;
    }

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    if (1 > size) {
        fp = fopen(filename, "r");
        if (!fp) {
            printf("Error opening file: %s\n", filename);
            return -1;
        }
        fscanf(fp, "%d", &size);

        a = (float *)malloc(size * size * sizeof(float));
        InitMat(fp, size, a, size, size);

        b = (float *)malloc(size * sizeof(float));
        InitAry(fp, b, size);

        fclose(fp);
    } else {
        printf("create input internally before create, size = %d \n", size);

        a = (float *)malloc(size * size * sizeof(float));
        create_matrix(a, size);

        b = (float *)malloc(size * sizeof(float));
        for (int i = 0; i < size; i++)
            b[i] = 1.0;
    }

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    if (!quiet && show_data) {
        printf("The input matrix a is:\n");
        PrintMat(a, size, size, size);

        printf("The input array b is:\n");
        PrintAry(b, size);
    }

    m = (float *)malloc(size * size * sizeof(float));
    finalVec = (float *)malloc(size * sizeof(float));

    InitPerRun(size, m);

    ForwardSub(a, b, m, size, timing);

    if (!quiet && show_data) {
        printf("The result of matrix m is: \n");
        PrintMat(m, size, size, size);
        printf("The result of matrix a is: \n");
        PrintMat(a, size, size, size);
        printf("The result of array b is: \n");
        PrintAry(b, size);

        BackSub(a, b, finalVec, size);
        printf("The final solution is: \n");
        PrintAry(finalVec, size);
    }

    free(m);
    free(a);
    free(b);
    free(finalVec);

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    return 0;
}
